    FireExtinguisher(
      id: 'fe-water-09',
      name: 'HydroBlast 9L Standard Water',
      description: 'Perfect for standard class A fire hazards involving materials like wood, paper, textiles, and coal. High-volume design ensures maximum coverage and rapid cooling of deep-seated embers.',
      price: 49.99,
