      pressure: '15 bar',
      stock: 60,
    ),
  ];

  String _searchQuery = '';
  String _selectedCategory = 'All';

  List<FireExtinguisher> get products => [..._products];

  List<FireExtinguisher> get filteredProducts {
    return _products.where((product) {
      final matchesSearch = product.name.toLowerCase().contains(_searchQuery.toLowerCase()) || product.description.toLowerCase().contains(_searchQuery.toLowerCase()) || product.fireClass.toLowerCase().contains(_searchQuery.toLowerCase());

      final matchesCategory = _selectedCategory == 'All' || product.category == _selectedCategory;

      return matchesSearch && matchesCategory;
    }).toList();
  }

  List<String> get categories => ['All', 'Dry Powder', 'CO2', 'Foam', 'Water', 'Wet Chemical'];

  String get searchQuery => _searchQuery;
  String get selectedCategory => _selectedCategory;

  void setSearchQuery(String query) {
    _searchQuery = query;
    notifyListeners();
  }

  void setSelectedCategory(String category) {
    _selectedCategory = category;
    notifyListeners();
  }

  void updateStock(String productId, int change) {
    final index = _products.indexWhere((p) => p.id == productId);
    if (index >= 0) {
      _products[index].stock += change;
      if (_products[index].stock < 0) _products[index].stock = 0;
      notifyListeners();
    }
  }

  void updateProduct(FireExtinguisher updatedProduct) {
    final index = _products.indexWhere((p) => p.id == updatedProduct.id);
    if (index >= 0) {
      _products[index] = updatedProduct;
      notifyListeners();
    }
  }

  void addProduct(FireExtinguisher product) {
    _products.add(product);
    notifyListeners();
  }

  void removeProduct(String productId) {
    _products.removeWhere((p) => p.id == productId);
    notifyListeners();
  }
}
